class ScienceSimulation {
    constructor(container, initialInputs) {
        this.container = container;
        this.canvas = document.createElement('canvas');
        this.ctx = this.canvas.getContext('2d');
        this.canvas.style.width = '100%';
        this.canvas.style.height = '100%';
        this.canvas.style.borderRadius = '12px';
        this.container.appendChild(this.canvas);

        // Setup listener
        window.addEventListener('resize', () => this.resizeCanvas());
        this.resizeCanvas();
    }

    resizeCanvas() {
        const rect = this.container.getBoundingClientRect();
        this.canvas.width = rect.width;
        this.canvas.height = rect.height;
    }

    getSteps(inputs) {
        const u = inputs.initialVelocity;
        const a = inputs.acceleration;
        const totalT = inputs.targetTime;
        const t = Math.min(inputs.currentTime, totalT);

        const v = u + a * t;
        const s = u * t + 0.5 * a * t * t;

        return [
            {
                title: "Step 1: Initial State",
                description: `A car starts with an initial velocity $u = \\mathbf{${u} \\text{ m/s}}$.\n\nThe uniform acceleration is $a = \\mathbf{${a} \\text{ m/s}^2}$. At $t = 0$, the car hasn't moved yet.`
            },
            {
                title: "Step 2: Velocity Equation",
                description: `As time passes, the velocity increases linearly at a rate of $a$.\n\nAt $t = ${t.toFixed(1)}$ seconds, the final velocity is:\n$$v = u + at = ${u} + (${a})(${t.toFixed(1)}) = \\mathbf{${v.toFixed(1)} \\text{ m/s}}$$`
            },
            {
                title: "Step 3: Distance Equation",
                description: `The total distance travelled is based on both the initial velocity component ($ut$) and the acceleration component ($\\frac{1}{2}at^2$).\n\nAt $t = ${t.toFixed(1)}$ seconds:\n$$s = (${u})(${t.toFixed(1)}) + \\frac{1}{2}(${a})(${t.toFixed(1)})^2 = \\mathbf{${s.toFixed(1)} \\text{ meters}}$$`
            }
        ];
    }

    render(inputs, stepIndex) {
        if (!this.ctx || !this.canvas.width) this.resizeCanvas();

        const w = this.canvas.width;
        const h = this.canvas.height;
        const ctx = this.ctx;

        const u = inputs.initialVelocity;
        const a = inputs.acceleration;
        const totalT = inputs.targetTime;
        let t = 0;

        // For Step 1, we show t=0 state.
        if (stepIndex === 0) {
            t = 0;
        } else {
            // Step 2 & 3 show the actual scrubbed time
            t = Math.min(inputs.currentTime, totalT);
        }

        const v = u + a * t;
        const s = u * t + 0.5 * a * t * t;
        const sMax = u * totalT + 0.5 * a * totalT * totalT;

        // Clear
        ctx.clearRect(0, 0, w, h);

        // Draw Background/Road
        const horizon = h * 0.6;
        ctx.fillStyle = '#1e293b';
        ctx.fillRect(0, horizon, w, h - horizon);

        // Road Markings
        ctx.strokeStyle = '#64748b';
        ctx.setLineDash([40, 40]);
        ctx.lineWidth = 4;
        ctx.beginPath();
        ctx.moveTo(0, horizon + 50);
        ctx.lineTo(w, horizon + 50);
        ctx.stroke();
        ctx.setLineDash([]);

        // Scale Position (keep car on screen)
        const padding = 80;
        const availableWidth = w - 2 * padding;
        const currentPosPercentage = sMax > 0 ? (s / sMax) : 0;
        const xPos = padding + currentPosPercentage * availableWidth;

        // Draw Car Shadow
        ctx.fillStyle = 'rgba(0,0,0,0.3)';
        ctx.beginPath();
        ctx.ellipse(xPos, horizon + 35, 40, 10, 0, 0, Math.PI * 2);
        ctx.fill();

        // Draw Car Body (Darker if t=0)
        ctx.fillStyle = stepIndex === 0 ? '#475569' : '#3b82f6';
        this.roundRect(ctx, xPos - 40, horizon - 10, 80, 40, 8, true);
        ctx.fillStyle = stepIndex === 0 ? '#64748b' : '#60a5fa';
        this.roundRect(ctx, xPos - 30, horizon - 35, 50, 30, 8, true);

        // Windows
        ctx.fillStyle = '#1e293b';
        ctx.fillRect(xPos + 5, horizon - 30, 10, 15);

        // Wheels
        ctx.fillStyle = '#000';
        ctx.beginPath();
        ctx.arc(xPos - 25, horizon + 30, 12, 0, Math.PI * 2);
        ctx.arc(xPos + 25, horizon + 30, 12, 0, Math.PI * 2);
        ctx.fill();

        // Wheel detail
        ctx.strokeStyle = '#fff';
        ctx.lineWidth = 2;
        const wheelRot = (s / 5);
        ctx.beginPath();
        ctx.moveTo(xPos - 25, horizon + 30);
        ctx.lineTo(xPos - 25 + Math.cos(wheelRot) * 12, horizon + 30 + Math.sin(wheelRot) * 12);
        ctx.moveTo(xPos + 25, horizon + 30);
        ctx.lineTo(xPos + 25 + Math.cos(wheelRot) * 12, horizon + 30 + Math.sin(wheelRot) * 12);
        ctx.stroke();

        // Velocity Arrow (Draw if step >= 1)
        if (stepIndex >= 1 && v > 0) {
            ctx.strokeStyle = '#10b981';
            ctx.lineWidth = 3;
            const arrowLen = Math.min(100, 20 + v * 3);
            ctx.beginPath();
            ctx.moveTo(xPos + 20, horizon - 20);
            ctx.lineTo(xPos + 20 + arrowLen, horizon - 20);

            ctx.lineTo(xPos + 20 + arrowLen - 10, horizon - 20 - 5);
            ctx.moveTo(xPos + 20 + arrowLen, horizon - 20);
            ctx.lineTo(xPos + 20 + arrowLen - 10, horizon - 20 + 5);
            ctx.stroke();

            ctx.fillStyle = '#10b981';
            ctx.font = 'bold 14px Inter';
            ctx.fillText('v', xPos + 15 + arrowLen, horizon - 15);
        }

        // HUD / Dashboard
        ctx.fillStyle = 'rgba(30, 41, 59, 0.9)';
        this.roundRect(ctx, 20, 20, 280, 160, 12, true);
        ctx.strokeStyle = '#3b82f6';
        ctx.lineWidth = 2;
        this.roundRect(ctx, 20, 20, 280, 160, 12, false);

        ctx.fillStyle = '#94a3b8';
        ctx.font = 'bold 16px Monospace';
        ctx.fillText(`TIME:         ${t.toFixed(2)} s`, 40, 55);
        ctx.fillText(`ACCELERATION: ${a.toFixed(2)} m/s²`, 40, 85);

        if (stepIndex >= 1) {
            ctx.fillStyle = '#10b981';
            ctx.font = 'bold 20px Monospace';
            ctx.fillText(`VELOCITY:    ${v.toFixed(2)} m/s`, 40, 120);
        } else {
            ctx.fillStyle = '#64748b';
            ctx.font = 'bold 20px Monospace';
            ctx.fillText(`VELOCITY:    ${u.toFixed(2)} m/s`, 40, 120);
        }

        if (stepIndex >= 2) {
            ctx.fillStyle = '#a855f7';
            ctx.font = 'bold 20px Monospace';
            ctx.fillText(`DISTANCE:    ${s.toFixed(2)} m`, 40, 150);
        }

        // Distance marker bar
        if (stepIndex >= 2 && s > 0) {
            ctx.strokeStyle = '#a855f7';
            ctx.lineWidth = 3;
            ctx.beginPath();
            ctx.moveTo(padding, horizon + 20);
            ctx.lineTo(xPos, horizon + 20);
            ctx.stroke();

            // tick marks
            ctx.beginPath();
            ctx.moveTo(padding, horizon + 15);
            ctx.lineTo(padding, horizon + 25);
            ctx.moveTo(xPos, horizon + 15);
            ctx.lineTo(xPos, horizon + 25);
            ctx.stroke();
        }

        // Start/End Markers
        ctx.fillStyle = '#94a3b8';
        ctx.font = '12px Sans-serif';
        ctx.fillText('0m', padding, horizon + 70);
        ctx.fillText(`${sMax.toFixed(0)}m`, padding + availableWidth - 20, horizon + 70);
    }

    roundRect(ctx, x, y, width, height, radius, fill) {
        ctx.beginPath();
        ctx.moveTo(x + radius, y);
        ctx.lineTo(x + width - radius, y);
        ctx.quadraticCurveTo(x + width, y, x + width, y + radius);
        ctx.lineTo(x + width, y + height - radius);
        ctx.quadraticCurveTo(x + width, y + height, x + width - radius, y + height);
        ctx.lineTo(x + radius, y + height);
        ctx.quadraticCurveTo(x, y + height, x, y + height - radius);
        ctx.lineTo(x, y + radius);
        ctx.quadraticCurveTo(x, y, x + radius, y);
        ctx.closePath();
        if (fill) ctx.fill(); else ctx.stroke();
    }
}
